      const note = await storage.navigateTemporarySoapNote(noteId, direction);
      if (!note) {
        return res.status(404).json({ error: 'No note found in that direction' });
      }

      // Verify the note belongs to the user
      if (note.userId !== userId) {
        return res.status(404).json({ error: 'No note found in that direction' });
      }

