  // Free Trial Management Routes
  // This endpoint now creates a Stripe checkout session for trial with payment method collection
  app.post("/api/trial/start", ensureAuthenticated, async (req: Request, res: Response) => {
    try {
      const userId = req.user!.id;
      const { tier = 'basic' } = req.body; // Default to basic tier
      
      // Check if user has already used their trial
      const trialStatus = await storage.getUserTrialStatus(userId);
      if (trialStatus.hasUsedTrial) {
        return res.status(400).json({ 
          error: "You have already used your free trial. Please upgrade to a paid membership for continued access." 
        });
      }

      // Use the Stripe instance already initialized at the top of the file
      // stripe is already imported and initialized
      
      // Get or create Stripe customer
      const user = await storage.getUser(userId);
      let customerId = user?.stripeCustomerId;
      
      if (!customerId) {
        const customer = await stripe.customers.create({
          email: user?.email || undefined,
          metadata: {
            userId: userId.toString(),
            username: user?.username || '',
          },
        });
        customerId = customer.id;
        await storage.updateStripeCustomerId(userId, customerId);
      }

      // Create or get existing products and prices
      let PRICE_IDS: Record<string, string> = {};
      
      try {
        // Check if products exist, if not create them
        const products = await stripe.products.list({ limit: 100 });
        
        const tiers = [
          { key: 'basic', name: 'Basic Plan', price: 3900, description: '10 PhysioGPT sessions/month' },
          { key: 'standard', name: 'Standard Plan', price: 9900, description: '100 PhysioGPT sessions/month' },
          { key: 'premium', name: 'Premium Plan', price: 19900, description: 'Unlimited PhysioGPT sessions' },
        ];
        
        for (const tierInfo of tiers) {
          let product = products.data.find(p => p.name === `PhysioAI ${tierInfo.name}`);
          
          if (!product) {
            product = await stripe.products.create({
              name: `PhysioAI ${tierInfo.name}`,
              description: tierInfo.description,
            });
          }
          
          // Check if price exists for this product
          const prices = await stripe.prices.list({ 
            product: product.id,
            limit: 100 
          });
          
          let price = prices.data.find(p => 
            p.unit_amount === tierInfo.price && 
            p.recurring?.interval === 'month'
          );
          
          if (!price) {
            price = await stripe.prices.create({
              product: product.id,
              unit_amount: tierInfo.price,
              currency: 'usd',
              recurring: {
                interval: 'month',
              },
            });
          }
          
          PRICE_IDS[tierInfo.key] = price.id;
        }
      } catch (error) {
        console.error("Error creating Stripe products/prices:", error);
        // Fallback to test price IDs if creation fails
        PRICE_IDS = {
          basic: 'price_1QZKBUQgGBJQM85ZJhVyIdGD',
          standard: 'price_1QZKBhQgGBJQM85ZXxoYjKcP',
          premium: 'price_1QZKBrQgGBJQM85ZPcqLJQI0',
        };
      }

      // Create checkout session with 14-day trial
      const session = await stripe.checkout.sessions.create({
        customer: customerId,
        payment_method_types: ['card'],
        line_items: [{
          price: PRICE_IDS[tier as keyof typeof PRICE_IDS],
          quantity: 1,
        }],
        mode: 'subscription',
        subscription_data: {
          trial_period_days: 14,
          metadata: {
            userId: userId.toString(),
            tier: tier,
          },
        },
        success_url: `${req.protocol}://${req.get('host')}/pricing?trial_activated=true`,
        cancel_url: `${req.protocol}://${req.get('host')}/pricing?trial_cancelled=true`,
        metadata: {
          userId: userId.toString(),
          tier: tier,
        },
      });

      res.json({ 
        checkoutUrl: session.url,
        sessionId: session.id,
        message: "Redirecting to secure checkout to start your 14-day free trial..."
      });
    } catch (error) {
      console.error("Error creating trial checkout session:", error);
      res.status(500).json({ error: "Unable to create checkout session for free trial" });
    }
  });

  app.get("/api/trial/status", ensureAuthenticated, async (req: Request, res: Response) => {
    try {
      const userId = req.user!.id;
      const trialStatus = await storage.getUserTrialStatus(userId);
      res.json(trialStatus);
    } catch (error) {
      console.error("Error getting trial status:", error);
      res.status(500).json({ error: "Unable to get trial status" });
    }
  });

  // Verify subscription after Stripe checkout
  app.post("/api/verify-subscription", ensureAuthenticated, async (req: Request, res: Response) => {
    try {
      const { sessionId } = req.body;
      const userId = req.user!.id;
      
      if (!sessionId) {
        return res.status(400).json({ error: "Session ID required" });
      }

      // Retrieve the checkout session from Stripe
      const session = await stripe.checkout.sessions.retrieve(sessionId, {
        expand: ['subscription', 'customer']
      });

      if (session.payment_status !== 'paid' && session.payment_status !== 'no_payment_required') {
        return res.status(400).json({ error: "Payment not completed" });
      }

      // Update user subscription details
      const subscription = session.subscription as any;
      const tier = session.metadata?.tier || 'basic';
      
      await storage.updateUserSubscription(userId, {
        stripeSubscriptionId: subscription?.id,
        stripeCustomerId: session.customer as string,
        membershipTier: tier as any,
        subscriptionStatus: subscription?.status || 'trialing',
        isOnTrial: true,
        trialStartDate: new Date(),
        trialEndDate: new Date(Date.now() + 14 * 24 * 60 * 60 * 1000), // 14 days from now
        hasUsedTrial: true,
        onboardingRequired: false, // Mark onboarding as complete
      });

      res.json({ 
        success: true,
        tier: tier,
        message: "Subscription verified successfully" 
      });
    } catch (error) {
      console.error("Error verifying subscription:", error);
      res.status(500).json({ error: "Unable to verify subscription" });
    }
  });

  // Complete onboarding (mark user as onboarded)
  app.post("/api/complete-onboarding", ensureAuthenticated, async (req: Request, res: Response) => {
    try {
      const userId = req.user!.id;
      
      // Update user to mark onboarding as complete
      await storage.updateUser(userId, {
        onboardingRequired: false
      });

      res.json({ 
        success: true,
        message: "Onboarding completed successfully" 
      });
    } catch (error) {
      console.error("Error completing onboarding:", error);
      res.status(500).json({ error: "Unable to complete onboarding" });
    }
  });

