  // Document status endpoint for polling
  app.get('/api/documents/status/:documentId', ensureAuthenticated, async (req, res) => {
    try {
      const { documentId } = req.params;
      const sessionId = req.query.sessionId as string;
      
      if (!sessionId) {
        // For simplicity, just return a status based on the document ID age
        const idTimestamp = parseInt(documentId.split('-')[1] || '0');
        const age = Date.now() - idTimestamp;
        
        // Assume documents take about 5-10 seconds to generate
        if (age < 5000) {
          return res.json({ status: 'generating', documentId });
        } else if (age < 30000) {
          return res.json({ 
            status: 'ready', 
            documentId,
            downloadUrl: `/api/documents/download/${documentId}`
          });
        } else {
          return res.json({ status: 'expired', documentId });
        }
      }
      
      // Get document from database
      const document = await storage.getGeneratedDocument(documentId);
      
      if (!document || document.sessionId !== sessionId) {
        return res.json({ status: 'not_found', documentId });
      }
      
      // Verify user owns this document
      if (document.userId !== req.user!.id) {
        return res.status(403).json({ error: 'Access denied' });
      }
      
      res.json({
        status: document.status,
        documentId: document.id,
        type: document.type,
        filename: document.filename,
        downloadUrl: document.status === 'ready' ? `/api/documents/download/${documentId}?sessionId=${sessionId}` : null,
        error: document.error
      });
    } catch (error) {
      console.error('Error checking document status:', error);
      res.status(500).json({ error: 'Failed to check document status' });
    }
  });
  
  // Document download endpoint
  app.get('/api/documents/download/:documentId', async (req, res) => {
    try {
      const { documentId } = req.params;
      const sessionId = req.query.sessionId as string;
      
      console.log(`Download request for document ${documentId} with session ${sessionId}`);
      
      // First try to get the document directly by ID
      let document = await storage.getGeneratedDocument(documentId);
      
      if (!document) {
        // If not found and sessionId provided, try session-based lookup
        if (sessionId) {
          console.log(`Document not found by ID, trying session ${sessionId}`);
          const documents = await storage.getGeneratedDocumentsBySession(sessionId);
          document = documents.find(d => d.id === documentId);
        }
      }
      
      // Check if document has either Word or PDF path
      const documentPath = document.pdfPath || document.wordPath;
      if (!document || !documentPath) {
        console.log(`Document not found: ${documentId}`);
        return res.status(404).json({ error: 'Document not found' });
      }
      
      console.log(`Found document: ${documentId} with path: ${documentPath}`);
      
      // Check if file exists
      const fs = await import('fs/promises');
      try {
        await fs.access(documentPath);
      } catch {
        return res.status(404).json({ error: 'Document file not found' });
      }
      
      // Determine content type and extension based on document type
      const isPdf = document.type === 'ahtr' || documentPath.endsWith('.pdf');
      const contentType = isPdf 
        ? 'application/pdf'
        : 'application/vnd.openxmlformats-officedocument.wordprocessingml.document';
      const extension = isPdf ? 'pdf' : 'docx';
      
      // Set headers for download
      res.setHeader('Content-Type', contentType);
      res.setHeader('Content-Disposition', `attachment; filename="${document.filename}.${extension}"`);
      
      // Stream the file
      const createReadStream = (await import('fs')).createReadStream;
      const stream = createReadStream(documentPath);
      stream.pipe(res);
    } catch (error) {
      console.error('Document download error:', error);
      res.status(500).json({ error: 'Failed to download document' });
    }
  });

  // Streaming Transcription WebSocket Server for long recordings
  const streamingWss = new WebSocketServer({ noServer: true });
  
  streamingWss.on('connection', async (ws: WebSocket, req) => {
    try {
      const url = new URL(req.url || '', `http://${req.headers?.host || 'localhost'}`);
      const userId = url.searchParams.get('userId') || '1'; // Default to user ID 1
      const sessionId = url.searchParams.get('sessionId') || uuidv4();
      
      console.log(`[Streaming Transcription] New connection - User: ${userId}, Session: ${sessionId}`);
      
      // Import streaming service
      const { streamingTranscriptionService } = await import('./streamingTranscriptionService');
      
      // Handle audio chunks
      ws.on('message', async (data: Buffer) => {
        try {
          // Process the audio chunk
          const result = await streamingTranscriptionService.processAudioChunk(
            sessionId,
            data,
            parseInt(userId)
          );
          
          // Send back transcription and SOAP sections if available
          if (result.transcript || result.soapSections) {
            ws.send(JSON.stringify({
              type: 'transcription',
              transcript: result.transcript,
              soapSections: result.soapSections,
              timestamp: new Date().toISOString()
            }));
          }
        } catch (error) {
          console.error('[Streaming Transcription] Error processing audio chunk:', error);
          ws.send(JSON.stringify({
            type: 'error',
            message: 'Error processing audio'
          }));
        }
      });
      
      // Handle finalization
      ws.on('close', async () => {
        try {
          const finalResult = await streamingTranscriptionService.flushSession(sessionId);
          console.log(`[Streaming Transcription] Session ${sessionId} finalized`);
        } catch (error) {
          console.error('[Streaming Transcription] Error finalizing session:', error);
        }
      });
      
      // Send initial acknowledgment
      ws.send(JSON.stringify({
        type: 'connected',
        sessionId,
        timestamp: new Date().toISOString()
      }));
      
    } catch (error) {
      console.error('[Streaming Transcription] Connection error:', error);
      ws.close(1011, 'Server error');
    }
  });
  
  console.log('🎙️ Streaming Transcription WebSocket server started on /ws/streaming-transcription');

  // Tournament WebSocket Server for real-time 1v1 matches
  const tournamentWss = new WebSocketServer({ noServer: true });
  
  tournamentWss.on('connection', async (ws: WebSocket, req) => {
    const url = new URL(req.url!, `http://${req.headers.host}`);
    const userId = url.searchParams.get('userId');
    
    if (!userId) {
      ws.close(1000, 'Missing userId');
      return;
    }
    
    console.log(`Tournament WebSocket client connected: ${userId}`);
    
    // Add client to tournament service
    const { realTimeTournamentService } = await import('./realTimeTournamentService');
    realTimeTournamentService.addConnection(parseInt(userId), ws);
    
    ws.on('close', () => {
      console.log(`Tournament WebSocket client disconnected: ${userId}`);
    });
  });

  console.log('⚔️ Tournament WebSocket server started on /ws/tournaments');

  // Phone Camera Relay WebSocket Server
  const phoneCameraRooms = new Map<string, { desktop: WebSocket | null; phone: WebSocket | null; region: string; createdAt: number }>();

  setInterval(() => {
    const now = Date.now();
    for (const [roomId, room] of phoneCameraRooms.entries()) {
      if (now - room.createdAt > 3600000) {
        if (room.desktop) room.desktop.close();
        if (room.phone) room.phone.close();
        phoneCameraRooms.delete(roomId);
      }
    }
  }, 300000);

  const phoneCameraWss = new WebSocketServer({ noServer: true });

  phoneCameraWss.on('connection', (ws: WebSocket, req) => {
    const url = new URL(req.url!, `http://${req.headers.host}`);
    const roomId = url.searchParams.get('room');
    const role = url.searchParams.get('role');
    console.log(`📱 Phone camera WebSocket connection: role=${role}, room=${roomId}`);

    if (!roomId || !role || !['desktop', 'phone'].includes(role)) {
      console.log(`📱 Phone camera WebSocket rejected: missing room or role`);
      ws.close(1008, 'Missing room or role parameter');
      return;
    }

    if (!phoneCameraRooms.has(roomId)) {
      phoneCameraRooms.set(roomId, { desktop: null, phone: null, region: 'full_body', createdAt: Date.now() });
    }

    const room = phoneCameraRooms.get(roomId)!;

    if (role === 'desktop') {
      if (room.desktop) room.desktop.close();
      room.desktop = ws;
      ws.send(JSON.stringify({ type: 'connected', role: 'desktop', roomId }));
      if (room.phone) {
        ws.send(JSON.stringify({ type: 'phone-connected' }));
        room.phone.send(JSON.stringify({ type: 'desktop-connected' }));
      }
    } else {
      if (room.phone) room.phone.close();
      room.phone = ws;
      ws.send(JSON.stringify({ type: 'connected', role: 'phone', roomId }));
      if (room.desktop) {
        ws.send(JSON.stringify({ type: 'desktop-connected' }));
        room.desktop.send(JSON.stringify({ type: 'phone-connected' }));
      }
    }

    ws.on('message', (data: any) => {
      try {
        const isBinary = data instanceof Buffer || data instanceof ArrayBuffer;
        if (isBinary) {
          if (role === 'phone' && room.desktop && room.desktop.readyState === WebSocket.OPEN) {
            room.desktop.send(data);
          }
          return;
        }
        const msg = JSON.parse(data.toString());

        if (msg.type === 'frame' && role === 'phone') {
          if (room.desktop && room.desktop.readyState === WebSocket.OPEN) {
            room.desktop.send(data.toString());
          }
        } else if (msg.type === 'region-change') {
          room.region = msg.region || 'full_body';
          const target = role === 'desktop' ? room.phone : room.desktop;
          if (target && target.readyState === WebSocket.OPEN) {
            target.send(JSON.stringify({ type: 'region-change', region: msg.region }));
          }
        } else if (msg.type === 'ping') {
          ws.send(JSON.stringify({ type: 'pong' }));
        } else {
          const target = role === 'desktop' ? room.phone : room.desktop;
          if (target && target.readyState === WebSocket.OPEN) {
            target.send(data.toString());
          }
        }
      } catch (e) {
        // ignore malformed messages
      }
    });

    ws.on('close', () => {
      if (room.desktop === ws) {
        room.desktop = null;
        if (room.phone && room.phone.readyState === WebSocket.OPEN) {
          room.phone.send(JSON.stringify({ type: 'desktop-disconnected' }));
        }
      } else if (room.phone === ws) {
        room.phone = null;
        if (room.desktop && room.desktop.readyState === WebSocket.OPEN) {
          room.desktop.send(JSON.stringify({ type: 'phone-disconnected' }));
        }
      }
      if (!room.desktop && !room.phone) {
        phoneCameraRooms.delete(roomId);
      }
    });
  });

