  // Real-time SOAP chunk processing endpoint
  app.post("/api/soap-notes/real-time-chunk", upload.single('audio'), async (req: Request, res: Response) => {
    try {
      const audioFile = req.file;
      const progressiveTranscript = req.body.progressiveTranscript || '';
      const isCompleteAudio = req.body.isCompleteAudio === 'true';
      // Parse existing SOAP sections to enhance rather than replace
      let existingSoapSections = { subjective: '', objective: '', assessment: '', plan: '' };
      try {
        if (req.body.existingSoapSections) {
          existingSoapSections = JSON.parse(req.body.existingSoapSections);
        }
      } catch (parseError) {
        console.log('[REAL-TIME] Could not parse existing SOAP sections, starting fresh');
      }

      if (!audioFile) {
        return res.status(400).json({ error: 'Audio chunk is required' });
      }

      console.log(`[REAL-TIME] Processing chunk: ${audioFile.size} bytes at ${new Date().toLocaleTimeString()}, mimetype: ${audioFile.mimetype}`);

      // Read the file buffer for the SOAP notes service
      const audioBuffer = fs.readFileSync(audioFile.path);
      
      // Use SOAP notes service transcription which handles the format better
      let transcriptionResult;
      try {
        transcriptionResult = await soapNotesService.transcribeAudio(audioBuffer, audioFile.originalname || 'chunk.webm');
      } catch (transcribeError) {
        console.error('[REAL-TIME] Transcription error:', transcribeError);
        // If transcription fails, return empty to keep the flow going
        transcriptionResult = { text: '' };
      }
      
      const fullTranscript = transcriptionResult.text || '';
      
      // Clean up temp file after transcription
      try {
        fs.unlinkSync(audioFile.path);
      } catch (cleanupError) {
        console.log('[REAL-TIME] Failed to clean up temp file:', cleanupError);
      }
      
      // Since we're now sending only the last 30 seconds as chunks (not complete audio),
      // the full transcript is already just the new chunk
      let chunkTranscript = fullTranscript;
      
      // If transcription failed or is empty, don't generate SOAP
      if (!chunkTranscript || chunkTranscript.includes('fallback transcription')) {
        console.log('[REAL-TIME] Skipping SOAP generation due to empty or fallback transcription');
        return res.json({
          transcription: '',
          soapSections: null,
          aiSuggestions: [],
          patientSwitch: { patientSwitchDetected: false, confidence: 0 },
          timestamp: new Date().toISOString()
        });
      }

      // Combine with progressive transcript for context
      const fullContext = progressiveTranscript 
        ? `${progressiveTranscript} ${chunkTranscript}`
        : chunkTranscript;

      // Generate/update SOAP sections using AI with the last 5 minutes of context
      const contextWords = fullContext.split(' ');
      const recentContext = contextWords.slice(-1500).join(' '); // ~5 minutes of speech

      console.log(`[REAL-TIME] Transcription complete: ${chunkTranscript.substring(0, 100)}...`);

      // Generate SOAP sections progressively - pass existing sections to enhance
      const soapSections = await soapNotesService.generateProgressiveSoapSections(
        recentContext,
        chunkTranscript,
        existingSoapSections // Pass existing sections to enhance rather than replace
      );
      console.log(`[REAL-TIME] SOAP sections enhanced`);

      // Generate AI suggestions based on current context
      const aiSuggestions = await soapNotesService.generateAISuggestions(recentContext);
      console.log(`[REAL-TIME] AI suggestions generated: ${aiSuggestions.length} suggestions`);

      // Check for patient switch
      const patientSwitch = await soapNotesService.analyzePatientSwitch(
        chunkTranscript,
        progressiveTranscript
      );

      const response = {
        transcription: chunkTranscript,
        soapSections,
        aiSuggestions,
        patientSwitch,
        timestamp: new Date().toISOString()
      };
      
      console.log(`[REAL-TIME] Sending response with SOAP sections:`, Object.keys(soapSections));
      res.json(response);
    } catch (error: any) {
      console.error("Error processing real-time chunk:", error);
      res.status(500).json({ error: error.message });
    }
  });

